async (page) => {
  // 1. Open inventory panel
  await page.evaluate(() => document.getElementById('inventory-button').click());
  await page.waitForTimeout(800);
  // 2. Click item slot 0 (Bronze Axe)
  await page.evaluate((idx) => {
    const slots = document.querySelectorAll('.item-slot');
    if (slots[idx]) slots[idx].click();
  }, 0);
  await page.waitForTimeout(800);
  // 3. Click equip button
  await page.evaluate(() => {
    const btn = document.querySelector('.action-equip');
    if (btn) btn.click();
  });
  await page.waitForTimeout(500);
  // 4. Close inventory panel
  await page.evaluate(() => document.getElementById('inventory-button').click());
  await page.waitForTimeout(500);
  // 5. Set attack style to Hack (index 0)
  await page.evaluate(() => window.game.player.setAttackStyle(0));
  await page.waitForTimeout(300);
  await page.screenshot({ path: '/tmp/kaetram_agent_0/state/screenshot.png', type: 'png' });
  return 'Equipped Bronze Axe and set Hack attack style';
}

async (page) => {
  // Walk to Programmer NPC
  await page.evaluate(({x, y}) => {
    const canvas = document.getElementById('canvas');
    canvas.dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
  }, { x: 792, y: 288 });
  await page.waitForTimeout(3000);
  await page.screenshot({ path: '/tmp/kaetram_agent_0/state/screenshot.png', type: 'png' });
  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  return state;
}

async (page) => {
  const click = (x, y) => page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
  }, {x, y});

  // Walk north (toward where Rat was seen)
  await click(640, 150);
  await page.waitForTimeout(2000);

  // Get state to find mobs
  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  const parsed = JSON.parse(state);
  const onScreenMobs = parsed.nearby_entities.filter(e => e.type === 3 && e.on_screen && e.click_x);

  if (onScreenMobs.length > 0) {
    const mob = onScreenMobs[0];
    await click(mob.click_x, mob.click_y);
    await page.waitForTimeout(8000);

    const state2 = await page.evaluate(() => JSON.stringify(window.__latestGameState));
    const parsed2 = JSON.parse(state2);
    return JSON.stringify({
      attacked: mob.name, hp_before: mob.hp,
      stats: parsed2.player_stats, last_xp: parsed2.last_xp_event, skills: parsed2.skills,
      mobs_now: parsed2.nearby_entities.filter(e=>e.type===3).slice(0,3).map(e=>({name:e.name,hp:e.hp,dist:e.distance}))
    });
  }
  return JSON.stringify({ mobs_on_screen: onScreenMobs.length, pos: parsed.player_position });
}

