async (page) => {
  // Attack Rat
  await page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
  }, { x: 216, y: 288 });
  await page.waitForTimeout(8000);

  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  const parsed = JSON.parse(state);
  // Find any on-screen mob after the fight
  const nextMob = parsed.nearby_entities.find(e => e.type === 3 && e.on_screen && e.click_x);

  // If there's another mob, attack it
  if (nextMob) {
    await page.evaluate(({x, y}) => {
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
    }, { x: nextMob.click_x, y: nextMob.click_y });
    await page.waitForTimeout(8000);
  }

  const state2 = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  const parsed2 = JSON.parse(state2);
  return JSON.stringify({
    pos: parsed2.player_position,
    stats: parsed2.player_stats,
    last_xp: parsed2.last_xp_event,
    last_combat: parsed2.last_combat,
    skills: parsed2.skills,
    kills: parsed2.nearby_entities.filter(e=>e.type===3).length
  });
}

async (page) => {
  // Find a Rat on screen
  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  const parsed = JSON.parse(state);
  const rat = parsed.nearby_entities.find(e => e.name === 'Rat' && e.on_screen && e.click_x);

  if (!rat) return 'no rat on screen';

  const click = (x, y) => page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
  }, {x, y});

  // Attack rat 5 times with short waits
  for (let i = 0; i < 5; i++) {
    await click(rat.click_x, rat.click_y);
    await page.waitForTimeout(2500);
  }

  const state2 = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  const parsed2 = JSON.parse(state2);
  return JSON.stringify({
    initial_rat_hp: rat.hp,
    pos: parsed2.player_position,
    stats: parsed2.player_stats,
    last_xp: parsed2.last_xp_event,
    last_combat: parsed2.last_combat,
    skills: parsed2.skills
  });
}

