async (page) => {
  // Check what elements are covering the canvas
  const info = await page.evaluate(() => {
    const canvas = document.getElementById('canvas');
    if (!canvas) return 'no canvas';
    const rect = canvas.getBoundingClientRect();

    // Check element at click point
    const el = document.elementFromPoint(640, 400);

    // Check for any open dialogs/menus
    const dialogs = document.querySelectorAll('[class*="dialog"], [class*="modal"], [class*="overlay"], [id*="quest"]');
    const openPanels = Array.from(dialogs).filter(d => {
      const style = window.getComputedStyle(d);
      return style.display !== 'none' && style.visibility !== 'hidden' && style.opacity !== '0';
    }).map(d => ({ id: d.id, class: d.className.substring(0,50) }));

    return JSON.stringify({
      canvasRect: { x: rect.x, y: rect.y, w: rect.width, h: rect.height },
      elementAtClick: el ? { id: el.id, tag: el.tagName, class: el.className.substring(0,50) } : null,
      openPanels: openPanels.slice(0,5)
    });
  });
  return info;
}

